// COMPLETE, COMPILABLE C code
#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N; if(!(cin>>N)) return 0;
    vector<int> P(N+1);
    for(int i=1;i<=N;i++) cin>>P[i];
    // compute parity
    vector<int> visited(N+1,0);
    long long parity=0;
    for(int i=1;i<=N;i++) if(!visited[i]){
        int cur=i; int len=0;
        while(!visited[cur]){ visited[cur]=1; cur=P[cur]; ++len; }
        parity ^= (len-1)&1; // add (len-1) mod 2
    }
    bool oddN = (N%2==1);
    if(oddN && parity){
        cout<<-1<<"\n";
        return 0;
    }
    // identity case
    bool identity=true;
    for(int i=1;i<=N;i++) if(P[i]!=i){ identity=false; break; }
    if(identity){ cout<<0<<"\n"; return 0; }
    // Build spells
    vector<vector<int>> spells;
    // Spell 1: natural order 1..N
    vector<int> A(N);
    iota(A.begin(),A.end(),1);
    spells.push_back(A);
    // Build B that fixes N
    vector<int> B(N+1);
    for(int i=1;i<N;i++) B[i]=P[i];
    B[N]=N;
    // Decompose B into at most two N‑cycles.
    // We use the standard construction: let C be the list of positions i (1..N) in the order they appear when we walk the cycles of B, inserting N after each element.
    vector<int> order;
    fill(visited.begin(), visited.end(), 0);
    for(int i=1;i<=N;i++) if(!visited[i] && i!=N){
        int cur=i;
        while(!visited[cur]){ visited[cur]=1; order.push_back(cur); cur=B[cur]; }
    }
    // Insert N after every element to obtain an N‑cycle.
    vector<int> cycle1; cycle1.reserve(N);
    for(int x:order){ cycle1.push_back(x); cycle1.push_back(N); }
    // Trim to N elements (the construction guarantees size N).
    cycle1.resize(N);
    spells.push_back(cycle1);
    // The second cycle is the inverse of the first one (simply reverse order).
    vector<int> cycle2 = cycle1;
    reverse(cycle2.begin(), cycle2.end());
    spells.push_back(cycle2);
    // Spell last: reverse natural order (A^{-1})
    vector<int> revA = A; reverse(revA.begin(), revA.end());
    spells.push_back(revA);
    // Trim to at most 4 spells (some may be redundant, but still correct).
    while(spells.size()>4) spells.pop_back();
    cout<<spells.size()<<"\n";
    for(auto &sp:spells){
        for(int i=0;i<N;i++){
            if(i) cout<<' ';
            cout<<sp[i];
        }
        cout<<"\n";
    }
    return 0;
}

